func deal_Fill(fill interface{}) (FillOption, interface{}, bool) {
	switch fill.(type) {
	case string:
		switch fill {
		case "null":
			return 0, nil, true
		case "none":
			return 1, nil, true
		case "previous":
			return 3, nil, true
		case "linear":
			return 4, nil, true
		default:
			return -1, nil, false
		}
	case int64:
		return 2, fill.(int64), true
	case float64:
		return 2, fill.(float64), true
	default:
		return -1, nil, false
	}
}

// Function that returns maximum depth of list of nodes, that may be nil.
func maxDepth(nodes ...nodeGuard) int {
	depth := 0
	for _, n := range nodes {
		if n != nil {
			depth = max(depth, n.Depth())
		}
	}
	return depth
}

